package com.example.samlsp.controller;

import com.example.samlsp.service.SamlService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;

import java.io.IOException;

@Controller
@RequestMapping("/saml")
public class SamlController {

    @Autowired
    private SamlService samlService;

    // This is the Assertion Consumer Service (ACS) endpoint
    // The IdP will POST the SAML Response to this URL
    @PostMapping("/acs")
    public void assertionConsumerService(@RequestParam(name = "SAMLResponse") String samlResponse,
                                         HttpServletRequest request,
                                         HttpServletResponse response) throws IOException {
        System.out.println("Received SAML Response at ACS endpoint.");
        try {
            // Process the SAML Response and create an authenticated session
            samlService.processSamlResponse(samlResponse, request);

            // Redirect to a protected page after successful authentication
            response.sendRedirect("/");
        } catch (Exception e) {
            System.err.println("Error processing SAML Response: " + e.getMessage());
            e.printStackTrace();
            // In a real application, you would render an error page
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Failed to process SAML Response");
        }
    }
}

